node --input-type=module <<'NODE'
import puppeteer from 'puppeteer-core';
const browser = await puppeteer.launch({executablePath:'/Applications/Google Chrome.app/Contents/MacOS/Google Chrome', headless:true, args:['--no-first-run','--no-default-browser-check']});
for (const [name, width, height] of [['desktop',1440,1000], ['mobile',390,844]]) {
  const page = await browser.newPage();
  await page.setViewport({width, height, deviceScaleFactor:1});
  const errors = [];
  page.on('console', msg => { if (msg.type() === 'error' && !msg.text().includes('favicon')) errors.push(msg.text()); });
  page.on('pageerror', err => errors.push(err.message));
  await page.goto('http://127.0.0.1:4173/', {waitUntil:'domcontentloaded', timeout:60000});
  await page.waitForFunction(() => document.querySelector('#status')?.textContent && !document.querySelector('#status').textContent.includes('Loading'), {timeout:60000});
  await page.screenshot({path:`/tmp/neo-${name}.png`});
  const metrics = await page.evaluate(() => {
    const canvas = document.querySelector('canvas');
    const c = document.createElement('canvas');
    c.width = 80; c.height = 80;
    const ctx = c.getContext('2d');
    ctx.drawImage(canvas, 0, 0, 80, 80);
    const data = ctx.getImageData(0, 0, 80, 80).data;
    let bright = 0, varied = new Set();
    for (let i=0; i<data.length; i+=4) {
      const key = `${data[i]>>4},${data[i+1]>>4},${data[i+2]>>4}`;
      varied.add(key);
      if (data[i] + data[i+1] + data[i+2] > 80) bright++;
    }
    return {status: document.querySelector('#status').textContent, stats: document.querySelector('#stats').textContent, results: document.querySelectorAll('.result').length, bright, colors: varied.size, bodyW: document.body.scrollWidth, bodyH: document.body.scrollHeight};
  });
  console.log(name, JSON.stringify({errors, metrics}, null, 2));
  await page.close();
}
await browser.close();
